import React, { useEffect, useState } from "react";
import { useSearchParams, useNavigate, Link } from "react-router-dom";

const VerifyEmail = () => {
  const [searchParams] = useSearchParams();
  const token = searchParams.get("token");
  const navigate = useNavigate();

  const [status, setStatus] = useState("verifying"); // verifying, success, error
  const [message, setMessage] = useState("");

  useEffect(() => {
    if (!token) {
      setStatus("error");
      setMessage("Invalid verification link.");
      return;
    }

    const verifyToken = async () => {
      try {
        const response = await fetch("http://localhost:5000/api/auth/verify-email", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ token }),
        });

        const data = await response.json();

        if (response.ok) {
          setStatus("success");
          setMessage(data.message || "Email verified successfully!");
        } else {
          setStatus("error");
          setMessage(data.message || "Failed to verify email. Token may be invalid or expired.");
        }
      } catch (error) {
        setStatus("error");
        setMessage("An error occurred. Please try again later.");
      }
    };

    verifyToken();
  }, [token]);

  return (
    <div style={{ display: "flex", justifyContent: "center", alignItems: "center", minHeight: "100vh", backgroundColor: "#f3f4f6" }}>
      <div style={{ padding: "40px", backgroundColor: "white", borderRadius: "8px", boxShadow: "0 4px 6px rgba(0, 0, 0, 0.1)", textAlign: "center", maxWidth: "400px", width: "100%" }}>
        {status === "verifying" && (
          <>
            <h2 style={{ fontSize: "24px", fontWeight: "bold", marginBottom: "16px" }}>Verifying your email...</h2>
            <div className="spinner" style={{ margin: "20px auto", width: "40px", height: "40px", border: "4px solid rgba(0,0,0,0.1)", borderRadius: "50%", borderTopColor: "#3b82f6", animation: "spin 1s ease-in-out infinite" }}></div>
            <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
          </>
        )}

        {status === "success" && (
          <>
            <div style={{ color: "#10b981", fontSize: "48px", marginBottom: "16px" }}>✓</div>
            <h2 style={{ fontSize: "24px", fontWeight: "bold", marginBottom: "16px", color: "#111827" }}>Verified!</h2>
            <p style={{ color: "#4b5563", marginBottom: "24px" }}>{message}</p>
            <Link to="/login" style={{ display: "inline-block", backgroundColor: "#2563eb", color: "white", padding: "10px 20px", borderRadius: "6px", textDecoration: "none", fontWeight: "500" }}>
              Go to Login
            </Link>
          </>
        )}

        {status === "error" && (
          <>
            <div style={{ color: "#ef4444", fontSize: "48px", marginBottom: "16px" }}>✗</div>
            <h2 style={{ fontSize: "24px", fontWeight: "bold", marginBottom: "16px", color: "#111827" }}>Verification Failed</h2>
            <p style={{ color: "#4b5563", marginBottom: "24px" }}>{message}</p>
            <Link to="/login" style={{ display: "inline-block", backgroundColor: "#e5e7eb", color: "#374151", padding: "10px 20px", borderRadius: "6px", textDecoration: "none", fontWeight: "500" }}>
              Back to Login
            </Link>
          </>
        )}
      </div>
    </div>
  );
};

export default VerifyEmail;
